const engagements = $('Get Engagements').all().map(i => i.json);
const global = $('Get Global Stats').first().json;
const weaknesses = $('Get Weakness Breakdown').all().map(i => i.json);

const dashboard = {
  generated_at: new Date().toISOString(),
  platform: 'RECON OS v1.0',
  global_health: {
    active_engagements: parseInt(global.active_engagements||0),
    total_clients: parseInt(global.total_clients||0),
    immediate_attention_open: parseInt(global.global_immediate||0),
    pending_validation: parseInt(global.global_pending_validation||0),
    overdue_retests: parseInt(global.global_overdue_retests||0),
    recurring_findings: parseInt(global.global_recurring||0),
    new_findings_7d: parseInt(global.new_findings_7d||0),
    global_avg_mttr_days: parseFloat(global.global_avg_mttr||0)
  },
  engagements: engagements.map(e => ({
    id: e.id,
    name: e.name,
    client: e.client_name,
    type: e.type,
    status: e.status,
    is_in_window: e.is_in_window,
    window: `${e.testing_window_start?.split('T')[0]} — ${e.testing_window_end?.split('T')[0]}`,
    assets: { total: parseInt(e.total_assets||0), tested: parseInt(e.assets_tested||0), coverage_pct: parseFloat(e.coverage_pct||0) },
    findings: {
      total: parseInt(e.total_findings||0),
      validated: parseInt(e.validated_findings||0),
      fixed: parseInt(e.verified_fixed||0),
      critical: parseInt(e.criticals||0),
      high: parseInt(e.highs||0),
      medium: parseInt(e.mediums||0),
      low: parseInt(e.lows||0)
    },
    avg_mttr_days: parseFloat(e.avg_mttr_days||0)
  })),
  weakness_heatmap: weaknesses.map(w => ({
    category: w.category,
    open_findings: parseInt(w.count),
    avg_risk_score: Math.round(parseFloat(w.avg_score||0)*100)/100
  }))
};

return [{ json: { dashboard } }];
